            selected_insurance_id = None

        if selected_insurance_id is not None:
            plan = next((ip for ip in insurance_plans if ip['insurance_id'] == selected_insurance_id), None)
            if plan:
                selected_plan = plan
                # Update reservation insurance_id and status Confirmed
                reservation['insurance_id'] = selected_insurance_id
                reservation['status'] = 'Confirmed'
                # Persist update
