@app.route('/insurance/<int:reservation_id>', methods=['GET', 'POST'])
def insurance_options(reservation_id):
    insurance_plans = read_insurances()
    reservations = read_reservations()

    reservation = next((res for res in reservations if res['reservation_id'] == reservation_id), None)
    if not reservation:
        # Invalid reservation id
        return redirect(url_for('dashboard'))

    selected_plan = None

    if request.method == 'POST':
        # Get selected insurance plan id from form
        selected_id = request.form.get('insurance_id')
        try:
            selected_insurance_id = int(selected_id)
        except Exception:
            selected_insurance_id = None

        if selected_insurance_id is not None:
            plan = next((ip for ip in insurance_plans if ip['insurance_id'] == selected_insurance_id), None)
            if plan:
                selected_plan = plan
                # Update reservation insurance_id and status Confirmed
                reservation['insurance_id'] = selected_insurance_id
                reservation['status'] = 'Confirmed'
                # Persist update
                write_reservations(reservations)
                # Redirect to reservation management after confirmation
                return redirect(url_for('reservation_management'))

    if reservation['insurance_id'] != 0:
        selected_plan = next((ip for ip in insurance_plans if ip['insurance_id'] == reservation['insurance_id']), None)

    return render_template('insurance.html', insurance_plans=insurance_plans, selected_plan=selected_plan, reservation_id=reservation_id)


