@app.route('/reservations', methods=['GET', 'POST'])
def reservation_management():
    reservations = read_reservations()
    sorted_by_date = False

    if request.method == 'POST':
        # Sort by date or modify or cancel reservation
        if 'sort_by_date' in request.form:
            # Sort reservations by rental pickup_date
            rentals = read_rentals()
            rental_map = {r['rental_id']: r for r in rentals}
            try:
                reservations.sort(key=lambda x: datetime.strptime(rental_map[x['rental_id']]['pickup_date'], '%Y-%m-%d'))
                sorted_by_date = True
            except Exception:
                pass

        # Check if modify or cancel operations
        if 'modify_reservation_id' in request.form:
            # For simplicity as no modification fields specified, just redirect back
            pass
        if 'cancel_reservation_id' in request.form:
            cancel_id = request.form.get('cancel_reservation_id')
            try:
                cancel_id_int = int(cancel_id)
                for res in reservations:
                    if res['reservation_id'] == cancel_id_int:
                        res['status'] = 'Cancelled'
                        write_reservations(reservations)
                        break
            except Exception:
                pass

    return render_template('reservations.html', reservations=reservations, sorted_by_date=sorted_by_date)


@app.route('/special_requests', methods=['GET', 'POST'])
def special_requests():
    reservations = read_reservations()
    submission_status = ''

    if request.method == 'POST':
        selected_reservation_id = request.form.get('reservation_id')
        driver_assistance = request.form.get('driver_assistance')
        gps_option = request.form.get('gps_option')
        child_seat_qty = request.form.get('child_seat_quantity')
        special_notes = request.form.get('special_notes', '').strip()

        try:
            reservation_id_int = int(selected_reservation_id)
            child_seat_qty_int = int(child_seat_qty) if child_seat_qty else 0

            special_texts = []
            if driver_assistance == 'on':
                special_texts.append('Driver assistance requested')
            if gps_option == 'on':
                special_texts.append('GPS requested')
            if child_seat_qty_int > 0:
                special_texts.append(f'Child seat quantity: {child_seat_qty_int}')
            if special_notes:
                special_texts.append(special_notes)

            full_special_requests = '; '.join(special_texts) if special_texts else ''

            # Update reservation
            found = False
            for res in reservations:
                if res['reservation_id'] == reservation_id_int:
                    res['special_requests'] = full_special_requests
                    found = True
                    break
            if found:
                write_reservations(reservations)
                submission_status = 'Special requests updated successfully.'
            else:
                submission_status = 'Reservation not found.'
        except Exception:
            submission_status = 'Invalid input. Please check your entries.'

    return render_template('special_requests.html', reservations=reservations, submission_status=submission_status)


